import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
  Home, User, FileText, Award, Users, GraduationCap,
  Settings, LogOut, Menu, X, ChevronDown, Shield,
  BookOpen, ClipboardList, Briefcase, BarChart3
} from 'lucide-react';

const Layout = ({ role }) => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [profileDropdownOpen, setProfileDropdownOpen] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  // Navigation items based on role
  const getNavItems = () => {
    switch (role) {
      case 'student':
        return [
          { path: '/student/dashboard', icon: Home, label: 'Dashboard' },
          { path: '/student/profile', icon: User, label: 'My Profile' },
          { path: '/student/violations', icon: FileText, label: 'My Violations' },
          { path: '/student/certificates', icon: Award, label: 'Certificates' },
        ];
      case 'teacher':
        return [
          { path: '/teacher/dashboard', icon: Home, label: 'Dashboard' },
          { path: '/teacher/profile', icon: User, label: 'My Profile' },
          { path: '/teacher/advisory', icon: Users, label: 'Advisory Students' },
          { path: '/teacher/encode-violation', icon: ClipboardList, label: 'Encode Violation' },
          { path: '/teacher/capstone', icon: BookOpen, label: 'Capstone Management' },
        ];
      case 'admin':
        return [
          { path: '/admin/dashboard', icon: Home, label: 'Dashboard' },
          { path: '/admin/students', icon: GraduationCap, label: 'Students' },
          { path: '/admin/teachers', icon: Users, label: 'Teachers' },
          { path: '/admin/violations', icon: ClipboardList, label: 'Violations' },
          { path: '/admin/users', icon: Shield, label: 'User Management' },
          { path: '/admin/logs', icon: BarChart3, label: 'System Logs' },
        ];
      default:
        return [];
    }
  };

  const navItems = getNavItems();

  const getRoleBadge = () => {
    const badges = {
      student: { color: 'bg-green-100 text-green-800', label: 'Student' },
      teacher: { color: 'bg-blue-100 text-blue-800', label: 'Teacher' },
      admin: { color: 'bg-purple-100 text-purple-800', label: 'Administrator' },
    };
    return badges[role] || { color: 'bg-gray-100 text-gray-800', label: role };
  };

  const badge = getRoleBadge();

  return (
    <div className="min-h-screen bg-secondary-50 flex">
      {/* Sidebar */}
      <aside
        className={`${
          sidebarOpen ? 'w-64' : 'w-20'
        } bg-white border-r border-secondary-200 transition-all duration-300 flex flex-col fixed h-full z-30`}
      >
        {/* Logo */}
        <div className="p-4 border-b border-secondary-200 flex items-center justify-between">
          {sidebarOpen && (
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-primary-600 rounded-lg flex items-center justify-center">
                <GraduationCap className="w-5 h-5 text-white" />
              </div>
              <span className="font-bold text-lg text-secondary-800">CCS MS</span>
            </div>
          )}
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-2 hover:bg-secondary-100 rounded-lg transition-colors"
          >
            {sidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
          </button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 p-4 space-y-1">
          {navItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              className={({ isActive }) =>
                `sidebar-link ${isActive ? 'sidebar-link-active' : ''} ${!sidebarOpen ? 'justify-center' : ''}`
              }
            >
              <item.icon className="w-5 h-5 flex-shrink-0" />
              {sidebarOpen && <span>{item.label}</span>}
            </NavLink>
          ))}
        </nav>

        {/* User Info */}
        <div className="p-4 border-t border-secondary-200">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-primary-100 rounded-full flex items-center justify-center flex-shrink-0">
              <User className="w-5 h-5 text-primary-600" />
            </div>
            {sidebarOpen && (
              <div className="flex-1 min-w-0">
                <p className="font-medium text-secondary-800 truncate">
                  {user?.firstName || user?.username || 'User'}
                </p>
                <span className={`text-xs px-2 py-0.5 rounded-full ${badge.color}`}>
                  {badge.label}
                </span>
              </div>
            )}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <div className={`flex-1 ${sidebarOpen ? 'ml-64' : 'ml-20'} transition-all duration-300`}>
        {/* Header */}
        <header className="bg-white border-b border-secondary-200 px-6 py-4 sticky top-0 z-20">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-xl font-semibold text-secondary-800">
                CCS Management System
              </h1>
              <p className="text-sm text-secondary-500">
                College of Computer Studies
              </p>
            </div>

            {/* Profile Dropdown */}
            <div className="relative">
              <button
                onClick={() => setProfileDropdownOpen(!profileDropdownOpen)}
                className="flex items-center gap-2 p-2 hover:bg-secondary-100 rounded-lg transition-colors"
              >
                <div className="w-8 h-8 bg-primary-100 rounded-full flex items-center justify-center">
                  <User className="w-4 h-4 text-primary-600" />
                </div>
                <ChevronDown className="w-4 h-4 text-secondary-500" />
              </button>

              {profileDropdownOpen && (
                <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-secondary-200 py-1 animate-fade-in">
                  <div className="px-4 py-2 border-b border-secondary-100">
                    <p className="font-medium text-secondary-800">
                      {user?.firstName || user?.username}
                    </p>
                    <p className="text-sm text-secondary-500">{user?.email}</p>
                  </div>
                  <button
                    onClick={handleLogout}
                    className="w-full flex items-center gap-2 px-4 py-2 text-red-600 hover:bg-red-50 transition-colors"
                  >
                    <LogOut className="w-4 h-4" />
                    Logout
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main className="p-6">
          <Outlet />
        </main>
      </div>

      {/* Overlay for mobile */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 z-20 lg:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}
    </div>
  );
};

export default Layout;
